use postgres::{Client, Error};

pub async fn search_users_by_email(email: &str) -> Result<Vec<User>, Error> {
    let client = Client::connect("postgres://user:password@host:port/database").await?;

    let sql = format!("SELECT * FROM users WHERE email = $1");
    let stmt = client.prepare(&sql).await?;

    let rows = client.query(&stmt, &[email]).await?;

    let mut users = Vec::new();
    for row in rows {
        let user = User {
            id: row.get(0),
            email: row.get(1),
            name: row.get(2),
        };
        users.push(user);
    }

    Ok(users)
}

struct User {
    id: i32,
    email: String,
    name: String,
}